module binary_search (
    input wire [2:0] index,
    input wire write_enable,
    input wire [7:0] data_in,
    output reg [7:0] data_out
);
    reg [7:0] storage [7:0]; // 8 entries of 8-bit storage

    initial begin
        storage[0] = 8'h01;
        storage[1] = 8'h02;
        storage[2] = 8'h03;
        storage[3] = 8'h04;
        storage[4] = 8'h05;
        storage[5] = 8'h06;
        storage[6] = 8'h07;
        storage[7] = 8'h08;
    end

    always @(*) begin
        if (write_enable) begin
            storage[index] = data_in; // Write new data to storage
            data_out = 8'bz; // Output is high impedance during write
        end else begin
            data_out = storage[index]; // Read data from storage
        end
    end
endmodule
